interface.signature:
interface DrillResult {
  id?: number;                                        // Auto-increment PK
  sessionId: number;                                  // FK to sessions.id
  timestamp: string;                                  // ISO 8601
  module: 'number_line' | 'spatial_rotation' | 'math_operations';
  difficulty: 'easy' | 'medium' | 'hard';
  isCorrect: boolean;
  timeToAnswer: number;                               // Milliseconds
  accuracy: number;                                   // Percentage (0-100)
  userAnswer?: number;                                // User's answer
  correctAnswer?: number;                             // Correct answer
  // Module-specific fields (optional)
  targetNumber?: number;                              // Number line
  shapeType?: string;                                 // Spatial rotation
  rotationDegrees?: number;                           // Spatial rotation
  isMirrored?: boolean;                               // Spatial rotation
  operation?: 'addition' | 'subtraction' | 'multiplication'; // Math operations
  problem?: string;                                   // e.g., "12 + 7"
}

// src/services/telemetry/logger.ts
export async function logSessionStart(sessionId: string | number, sessionType: 'quick' | 'full', drillCount: number): Promise;
export async function logDrillComplete(module: string, data: { accuracy: number; difficulty: string; isCorrect: boolean; timeToAnswer: number }): Promise;
export async function logSessionEnd(data: { accuracy: number; duration: number; confidenceChange: number | null; drillCount: number }): Promise;
export async function logSessionPause(currentDrillIndex: number): Promise;
export async function logSessionResume(): Promise;

// src/services/storage/exportData.ts
export async function exportSessionData(sessionId: number): Promise<{
  session: Session;
  drillResults: DrillResult[];
  telemetryLogs: TelemetryLog[];
}>;

// src/services/storage/maintenance.ts or db.ts
export async function cleanOldSessions(retentionDays?: number): Promise;
// Default retentionDays = 365
// Returns count of deleted sessions
